import React, { useState, useMemo } from 'react';
import { MOCK_VIDEOS } from '../constants';
import VideoCard from '../components/VideoCard';

const Episodes: React.FC = () => {
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [filterNeighborhood, setFilterNeighborhood] = useState<string>('all');
  const [sortBy, setSortBy] = useState<string>('recent');

  const categories = useMemo(() => ['all', ...new Set(MOCK_VIDEOS.map(v => v.category))], []);
  const neighborhoods = useMemo(() => ['all', ...new Set(MOCK_VIDEOS.map(v => v.neighborhood))], []);

  const filteredAndSortedVideos = useMemo(() => {
    let videos = [...MOCK_VIDEOS];

    if (filterCategory !== 'all') {
      videos = videos.filter(v => v.category === filterCategory);
    }

    if (filterNeighborhood !== 'all') {
      videos = videos.filter(v => v.neighborhood === filterNeighborhood);
    }

    if (sortBy === 'recent') {
      videos.sort((a, b) => new Date(b.uploadDate).getTime() - new Date(a.uploadDate).getTime());
    } else if (sortBy === 'views') {
      videos.sort((a, b) => b.views - a.views);
    }

    return videos;
  }, [filterCategory, filterNeighborhood, sortBy]);

  const FilterSelect: React.FC<{ label: string; value: string; onChange: (e: React.ChangeEvent<HTMLSelectElement>) => void; options: string[] }> = ({ label, value, onChange, options }) => (
    <div className="flex flex-col gap-1 w-full">
        <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">{label}</label>
        <select
            value={value}
            onChange={onChange}
            className="w-full bg-gray-100 border-none text-gray-800 font-bold py-3 px-4 rounded-xl focus:ring-2 focus:ring-yellow-500 focus:bg-white transition-all appearance-none cursor-pointer"
        >
            {options.map(option => (
                <option key={option} value={option}>{option === 'all' ? `Todos` : option}</option>
            ))}
        </select>
    </div>
  );

  return (
    <div className="bg-white min-h-screen">
      <div className="bg-gray-900 py-20 text-center">
          <div className="container mx-auto px-6">
              <h1 className="text-5xl font-black text-white uppercase tracking-tighter">Explorar <span className="text-yellow-500">Episódios</span></h1>
              <p className="text-gray-400 mt-4 max-w-xl mx-auto">Filtrados por nicho, região ou popularidade. Descubra o melhor de Capão da Canoa.</p>
          </div>
      </div>

      <div className="container mx-auto px-6 py-12">
        {/* Modern Filters Bar */}
        <div className="bg-white p-6 rounded-3xl shadow-xl border border-gray-100 -mt-20 relative z-30 mb-16 grid grid-cols-1 md:grid-cols-3 gap-6">
            <FilterSelect label="Categoria" value={filterCategory} onChange={e => setFilterCategory(e.target.value)} options={categories} />
            <FilterSelect label="Bairro / Região" value={filterNeighborhood} onChange={e => setFilterNeighborhood(e.target.value)} options={neighborhoods} />
            <FilterSelect label="Ordenar por" value={sortBy} onChange={e => setSortBy(e.target.value)} options={['recent', 'views']} />
        </div>

        {/* Video Grid */}
        {filteredAndSortedVideos.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
            {filteredAndSortedVideos.map(video => (
              <VideoCard key={video.id} video={video} />
            ))}
          </div>
        ) : (
          <div className="text-center py-24 bg-gray-50 rounded-3xl">
            <svg className="w-16 h-16 text-gray-300 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
