import React, { createContext, useContext, useState, useEffect } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  login: (userData: User, token: string) => void;
  logout: () => void;
  isAuthenticated: boolean;
  loading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedUser = localStorage.getItem('rota_local_user');
    const token = localStorage.getItem('rota_local_token');
    if (savedUser && token) {
      setUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const login = (userData: User, token: string) => {
    setUser(userData);
    localStorage.setItem('rota_local_user', JSON.stringify(userData));
    localStorage.setItem('rota_local_token', token);
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('rota_local_user');
    localStorage.removeItem('rota_local_token');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated: !!user, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth deve ser usado dentro de um AuthProvider');
  }
  return context;
};

import { API_BASE_URL, MOCK_VIDEOS, MOCK_BUSINESSES, MOCK_BLOG_POSTS } from '../constants';
import type { Video, Business, BlogPost, User, AuthResponse } from '../types';

export const DataService = {
  // Auth
  async login(email: string, password: string): Promise<AuthResponse> {
    const response = await fetch(`${API_BASE_URL}/login.php`, {
      method: 'POST',
      body: JSON.stringify({ email, password }),
      headers: { 'Content-Type': 'application/json' }
    });
    if (!response.ok) throw new Error('Credenciais inválidas');
    return await response.json();
  },

  async register(name: string, email: string, password: string): Promise<AuthResponse> {
    const response = await fetch(`${API_BASE_URL}/register.php`, {
      method: 'POST',
      body: JSON.stringify({ name, email, password }),
      headers: { 'Content-Type': 'application/json' }
    });
    if (!response.ok) throw new Error('Erro ao criar conta');
    return await response.json();
  },

  // Content
  async getVideos(): Promise<Video[]> {
    try {
      const response = await fetch(`${API_BASE_URL}/get_videos.php`);
      if (!response.ok) throw new Error('Falha na rede');
      return await response.json();
    } catch (error) {
      console.warn('API não encontrada. Usando mocks.', error);
      return MOCK_VIDEOS;
    }
  },

  async getBusinessById(id: string): Promise<Business | null> {
    try {
      const response = await fetch(`${API_BASE_URL}/get_business.php?id=${id}`);
      if (!response.ok) throw new Error('Falha na rede');
      return await response.json();
    } catch (error) {
      return MOCK_BUSINESSES.find(b => b.id === id) || null;
    }
  },

  async getBlogPosts(): Promise<BlogPost[]> {
    try {
      const response = await fetch(`${API_BASE_URL}/get_posts.php`);
      if (!response.ok) throw new Error('Falha na rede');
      return await response.json();
    } catch (error) {
      return MOCK_BLOG_POSTS;
    }
  }
};

